// Distributed job scheduling with Spring
@Service
public class DistributedScheduler {
  @Scheduled(fixedDelay = 1000)
  public void pollJobs() {
    List<Job> pending = jobRepository.findPendingJobs();
    for (Job job : pending) {
      if (acquireLock(job.getId())) {
        try {
          executeJob(job);
          job.setStatus(JobStatus.COMPLETED);
        } catch (Exception e) {
          job.setRetries(job.getRetries() + 1);
          job.setNextRetryTime(calculateBackoff(job.getRetries()));
        } finally {
          releaseLock(job.getId());
        }
        jobRepository.save(job);
      }
    }
  }
}

// SLO Metrics Calculation
@Service
public class SLOCalculator {
  public SLOStatus calculateSLO(String service, Duration window) {
    MetricQueryResult result = prometheusClient.query(
      "sum(rate(requests_total{service='" + service + "'}[" + window + "]))"
    );
    double totalRequests = result.getValue();
    double failedRequests = prometheusClient.query(
      "sum(rate(requests_failed{service='" + service + "'}[" + window + "]))"
    ).getValue();
    double slowRequests = prometheusClient.query(
      "sum(rate(requests_slow{service='" + service + "'}[" + window + "]))"
    ).getValue();

    double successRate = (totalRequests - failedRequests - slowRequests) / totalRequests;
    double sloTarget = 0.995; // 99.5% SLO
    double errorBudget = (1 - sloTarget) * totalRequests;

    return new SLOStatus(successRate, sloTarget, errorBudget);
  }
}

