// Micrometer metrics with Spring
@RestController
public class PaymentController {
  private final MeterRegistry registry;

  @PostMapping("/pay")
  public ResponseEntity<Payment> pay(@RequestBody PaymentReq req) {
    Timer.Sample sample = Timer.start(registry);
    try {
      Payment p = paymentService.process(req);
      registry.counter("payments.success").increment();
      return ok(p);
    } catch (Exception e) {
      registry.counter("payments.failed").increment();
      throw e;
    } finally {
      sample.stop(Timer.builder("payment.latency")
        .publishPercentiles(0.5, 0.99)
        .register(registry));
    }
  }
}

