@FunctionalInterface
public interface Calculator {
  int calculate(int a, int b); // One abstract method

  default int add(int a, int b) { // Default allowed
    return calculate(a, b);
  }

  static int multiply(int a, int b) { // Static allowed
    return a * b;
  }
}

// WRONG: Multiple abstract methods
@FunctionalInterface
public interface BadInterface {
  void method1();
  void method2(); // Compilation error!
}

// Using functional interface with lambda
Calculator adder = (a, b) -> a + b; // Lambda works
System.out.println(adder.calculate(5, 3)); // 8

// Existing functional interfaces
Function<Integer, Integer> double_it = x -> x * 2;
Predicate<Integer> isPositive = x -> x > 0;
Consumer<String> print = System.out::println;
Supplier<String> hello = () -> "Hello";

