// Multiple defaults, one abstract
@FunctionalInterface
public interface DataProcessor {
  // Abstract - lambda MUST implement
  Result process(Data input);

  // Defaults - lambda inherits automatically
  default void validate(Data input) {
    if (input == null) throw new IllegalArgumentException();
  }

  default Result processWithValidation(Data input) {
    validate(input);
    return process(input);
  }

  default Result processOrDefault(Data input, Result fallback) {
    try {
      return process(input);
    } catch (Exception e) {
      return fallback;
    }
  }
}

// Lambda only implements the abstract method
DataProcessor processor = (data) -> new Result("Processed");

// Defaults are inherited
processor.validate(data); // Works
processor.processWithValidation(data); // Works
processor.processOrDefault(data, fallback); // Works
